  "time_constraints": [
    "_TABLE_SUFFIX BETWEEN '20210101' AND '20210107'",
    "_TABLE_SUFFIX BETWEEN '20210106' AND '20210107'"
  ],
  "grouping": [
    "user_pseudo_id"
  ],
  "sorting": [],
  "limit": null,
  "ambiguity_points": [
    "The engagement_time_msec is stored as part of event_params array, not as a direct column.",
    "Need to perform two separate aggregations to find users with positive engagement in 7-day period but not in 2-day period."
  ],
  "expected_shape": "single_value"
}

